import{_ as t,c as e,o as i,a1 as l}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"クイックスタート: Antigravity Auth のインストールと設定 | OpenCode","description":"Antigravity Auth プラグインのインストールと設定方法を学習します。10分以内に Google OAuth 認証を完了し、最初のモデルリクエストを送信して、Claude と Gemini モデルへのアクセスが正常に動作することを確認します。","frontmatter":{"title":"クイックスタート: Antigravity Auth のインストールと設定 | OpenCode","sidebarTitle":"10分で起動","subtitle":"クイックスタート: Antigravity Auth のインストールと設定","description":"Antigravity Auth プラグインのインストールと設定方法を学習します。10分以内に Google OAuth 認証を完了し、最初のモデルリクエストを送信して、Claude と Gemini モデルへのアクセスが正常に動作することを確認します。","order":1},"headers":[],"relativePath":"ja/NoeFabris/opencode-antigravity-auth/start/index.md","filePath":"ja/NoeFabris/opencode-antigravity-auth/start/index.md"}'),r={name:"ja/NoeFabris/opencode-antigravity-auth/start/index.md"};function o(n,a,h,u,s,d){return i(),e("div",null,[...a[0]||(a[0]=[l('<h1 id="クイックスタート" tabindex="-1">クイックスタート <a class="header-anchor" href="#クイックスタート" aria-label="Permalink to &quot;クイックスタート&quot;">​</a></h1><p>この章では、Antigravity Auth プラグインをゼロから使い始める方法を説明します。プラグインの中核的な価値を理解し、インストールと OAuth 認証を完了し、最初のモデルリクエストを送信して設定が正常に動作することを確認します。</p><h2 id="学習パス" tabindex="-1">学習パス <a class="header-anchor" href="#学習パス" aria-label="Permalink to &quot;学習パス&quot;">​</a></h2><p>以下の順序で学習してください。各ステップは前のステップに基づいて構築されています：</p><h3 id="_1-プラグインの紹介" tabindex="-1">1. <a href="./what-is-antigravity-auth/">プラグインの紹介</a> <a class="header-anchor" href="#_1-プラグインの紹介" aria-label="Permalink to &quot;1. [プラグインの紹介](./what-is-antigravity-auth/)&quot;">​</a></h3><p>Antigravity Auth プラグインの中核的な価値、適用シナリオ、リスク警告について理解します。</p><ul><li>プラグインがあなたのユースケースに適しているかどうかを判断する</li><li>サポートされている AI モデルを確認する（Claude Opus 4.5、Sonnet 4.5、Gemini 3 Pro/Flash）</li><li>使用上のリスクと注意事項を明確にする</li></ul><h3 id="_2-クイックインストール" tabindex="-1">2. <a href="./quick-install/">クイックインストール</a> <a class="header-anchor" href="#_2-クイックインストール" aria-label="Permalink to &quot;2. [クイックインストール](./quick-install/)&quot;">​</a></h3><p>5分でプラグインのインストールと初回認証を完了します。</p><ul><li>2つのインストール方法（AI アシスタント / 手動設定）</li><li>モデル定義の設定</li><li>Google OAuth 認証の実行</li></ul><h3 id="_3-oauth-2-0-pkce-認証" tabindex="-1">3. <a href="./first-auth-login/">OAuth 2.0 PKCE 認証</a> <a class="header-anchor" href="#_3-oauth-2-0-pkce-認証" aria-label="Permalink to &quot;3. [OAuth 2.0 PKCE 認証](./first-auth-login/)&quot;">​</a></h3><p>OAuth 2.0 PKCE 認証フローを理解し、初回ログインを完了します。</p><ul><li>PKCE 認証のセキュリティメカニズムを理解する</li><li>初回ログインを完了して API アクセス権限を取得する</li><li>トークンリフレッシュの自動処理について理解する</li></ul><h3 id="_4-最初のリクエスト" tabindex="-1">4. <a href="./first-request/">最初のリクエスト</a> <a class="header-anchor" href="#_4-最初のリクエスト" aria-label="Permalink to &quot;4. [最初のリクエスト](./first-request/)&quot;">​</a></h3><p>最初のモデルリクエストを送信し、インストールの成功を確認します。</p><ul><li>最初の Antigravity モデルリクエストを送信する</li><li><code>--model</code> と <code>--variant</code> パラメータを理解する</li><li>一般的なモデルリクエストエラーをトラブルシュートする</li></ul><h2 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h2><p>この章を始める前に、以下を確認してください：</p><ul><li>✅ OpenCode CLI がインストールされていること（<code>opencode</code> コマンドが使用可能）</li><li>✅ 使用可能な Google アカウントがあること（OAuth 認証用）</li></ul><h2 id="次のステップ" tabindex="-1">次のステップ <a class="header-anchor" href="#次のステップ" aria-label="Permalink to &quot;次のステップ&quot;">​</a></h2><p>クイックスタートを完了したら、以下が可能になります：</p><ul><li><strong><a href="./../platforms/available-models/">利用可能なモデルを確認する</a></strong> — サポートされているすべてのモデルとそのバリアント設定を確認する</li><li><strong><a href="./../advanced/multi-account-setup/">複数アカウントを設定する</a></strong> — 複数の Google アカウントを設定してクォータをプール化する</li><li><strong><a href="./../faq/common-auth-issues/">一般的な認証問題</a></strong> — 問題が発生した場合はトラブルシュートガイドを参照する</li></ul>',22)])])}const f=t(r,[["render",o]]);export{p as __pageData,f as default};
